const auth = firebase.auth();
const firestore = firebase.firestore();

function useTheme() {
  const [themeColor, setThemeColor] = useState(localStorage.getItem('themeColor') || '#5865F2');
  useEffect(() => { localStorage.setItem('themeColor', themeColor); }, [themeColor]);
  return [themeColor, setThemeColor];
}

function App() {
  const [user] = useAuthState(auth);
  const [themeColor, setThemeColor] = useTheme();

  // Sync user profile to DB for member list
  useEffect(() => {
    if (user) {
      firestore.collection('users').doc(user.uid).set({
        uid: user.uid,
        email: user.email || '',
        displayName: user.displayName || (user.email ? user.email.split('@')[0] : 'Anonymous'),
        photoURL: user.photoURL || 'https://api.adorable.io/avatars/23/abott@adorable.png',
        lastActive: firebase.firestore.FieldValue.serverTimestamp()
      }, { merge: true });
    }
  }, [user]);

  return (
    <div className="App" style={{'--accent-color': themeColor}}>
      {user ? <MainApp themeColor={themeColor} setThemeColor={setThemeColor} /> : <AuthScreen themeColor={themeColor} />}
    </div>
  );
}

function AuthScreen({ themeColor }) {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleEmailAuth = async (e) => {
    e.preventDefault();
    setError('');
    try {
      if (isLogin) await auth.signInWithEmailAndPassword(email, password);
      else await auth.createUserWithEmailAndPassword(email, password);
    } catch (err) { setError(err.message); }
  };

  const signInWithGoogle = () => {
    const provider = new firebase.auth.GoogleAuthProvider();
    auth.signInWithPopup(provider);
  };

  return (
    <div className="signin-container">
      <div style={{background: '#2f3136', padding: '32px', borderRadius: '12px', width: '320px', boxShadow: '0 8px 24px rgba(0,0,0,0.2)'}}>
        <h2 style={{marginTop: 0, textAlign: 'center', color: '#fff'}}>{isLogin ? 'Welcome Back' : 'Create an Account'}</h2>
        <form onSubmit={handleEmailAuth} style={{display: 'flex', flexDirection: 'column', gap: '16px', padding: 0, background: 'transparent'}}>
          <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} required style={{padding: '12px', borderRadius: '8px', border: 'none', background: '#202225', color: '#fff'}} />
          <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} required style={{padding: '12px', borderRadius: '8px', border: 'none', background: '#202225', color: '#fff'}} />
          <button type="submit" className="sign-in" style={{display: 'block', backgroundColor: themeColor}}>{isLogin ? 'Login' : 'Sign Up'}</button>
        </form>
        {error && <p style={{color: '#ed4245', fontSize: '13px', textAlign: 'center'}}>{error}</p>}
        <p style={{textAlign: 'center', fontSize: '14px', cursor: 'pointer', color: themeColor, marginTop: '16px'}} onClick={() => setIsLogin(!isLogin)}>
          {isLogin ? 'Need an account? Register' : 'Already have an account? Login'}
        </p>
        <hr style={{borderColor: '#202225', margin: '24px 0'}} />
        <button className="sign-in" style={{width: '100%', backgroundColor: '#fff', color: '#000'}} onClick={signInWithGoogle}>Continue with Google</button>
      </div>
    </div>
  );
}

function SettingsModal({ close, themeColor, setThemeColor }) {
  const [name, setName] = useState((auth.currentUser && auth.currentUser.displayName) ? auth.currentUser.displayName : '');
  const [photo, setPhoto] = useState((auth.currentUser && auth.currentUser.photoURL) ? auth.currentUser.photoURL : '');
  const [newPassword, setNewPassword] = useState('');
  const [notificationsEnabled, setNotificationsEnabled] = useState(Notification.permission === 'granted');
  const colors = ['#5865F2', '#ed4245', '#3ba55c', '#fee75c', '#eb459e', '#9b59b6'];

  const saveSettings = async () => {
    await auth.currentUser.updateProfile({ displayName: name, photoURL: photo });
    firestore.collection('users').doc(auth.currentUser.uid).update({ displayName: name, photoURL: photo });
    close();
  };

  const requestNotifications = () => {
    if (!("Notification" in window)) {
      alert("This browser does not support desktop notification");
    } else if (Notification.permission !== "denied") {
      Notification.requestPermission().then(permission => {
        setNotificationsEnabled(permission === "granted");
      });
    }
  };

  return (
    <div className="settings-overlay">
      <div className="settings-layout">
        <div className="settings-sidebar">
          <div className="settings-nav">
            <h4>User Settings</h4>
            <div className="settings-tab active">My Account</div>
            <div className="settings-divider"></div>
            <div className="settings-tab logout" onClick={() => auth.signOut()}>Log Out</div>
          </div>
        </div>
        <div className="settings-content">
          <button className="close-settings" onClick={close}>X</button>
          <h2>My Account</h2>
          
          <div className="settings-card">
            <h3>Profile</h3>
            <img src={photo || 'https://api.adorable.io/avatars/23/abott@adorable.png'} alt="Preview" style={{width: '80px', height: '80px', borderRadius: '50%', objectFit: 'cover'}} />
            <div className="settings-group">
              <label>DISPLAY NAME</label>
              <input value={name} onChange={(e) => setName(e.target.value)} />
            </div>
            <div className="settings-group">
              <label>AVATAR URL</label>
              <input value={photo} onChange={(e) => setPhoto(e.target.value)} />
            </div>
            <button className="save-btn" onClick={saveSettings} style={{backgroundColor: themeColor, borderRadius: '8px', border: 'none'}}>Save Profile</button>
          </div>

          <div className="settings-card">
            <h3>App Preferences</h3>
            <div className="settings-group">
              <label>THEME COLOR</label>
              <div className="color-picker">
                {colors.map(c => (
                  <div key={c} className="color-swatch" style={{backgroundColor: c, borderColor: themeColor === c ? '#fff' : 'transparent'}} onClick={() => setThemeColor(c)} />
                ))}
              </div>
            </div>
            <div className="settings-divider" style={{margin: '15px 0'}}></div>
            <div className="toggle-row" style={{padding: 0, background: 'transparent'}}>
              <div>
                <strong>Desktop/Mobile Notifications</strong>
                <span>Get alerts for new messages while app is open</span>
              </div>
              <button onClick={requestNotifications} style={{background: notificationsEnabled ? '#3ba55c' : '#4f545c', padding: '8px 16px', color: 'white'}}>
                {notificationsEnabled ? 'Enabled' : 'Enable Notifications'}
              </button>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
}

function ServerSettingsModal({ server, close, themeColor }) {
  const [name, setName] = useState(server.name);
  const [icon, setIcon] = useState(server.icon);
  const [isPrivate, setIsPrivate] = useState(server.isPrivate || false);
  const [inviteCode, setInviteCode] = useState(server.inviteCode || '');

  const saveServer = async () => {
    let code = inviteCode;
    if (isPrivate && !code) code = Math.random().toString(36).substring(2, 8).toUpperCase();
    
    await firestore.collection('servers').doc(server.id).update({
      name, icon: icon || name.charAt(0).toUpperCase(), isPrivate,
      inviteCode: isPrivate ? code : null,
      members: isPrivate && !server.members ? [auth.currentUser.uid] : (server.members || [])
    });
    close();
  };

  return (
    <div className="settings-overlay" style={{zIndex: 1001}}>
      <div className="server-modal-container">
        <h2 style={{margin: 0, color: '#fff'}}>Server Settings</h2>
        <div className="settings-group">
          <label>SERVER NAME</label>
          <input value={name} onChange={(e) => setName(e.target.value)} style={{background: '#202225', border: 'none', padding: '12px', borderRadius: '8px', color: '#fff', width: '100%', boxSizing: 'border-box'}} />
        </div>
        <div className="toggle-row">
          <div>
            <strong>Private Server</strong>
            <span>Only invited members can join</span>
          </div>
          <div className={`toggle-switch ${isPrivate ? 'on' : ''}`} onClick={() => setIsPrivate(!isPrivate)}>
            <div className="toggle-knob"></div>
          </div>
        </div>
        {isPrivate && (
          <div className="settings-group">
            <label>INVITE CODE</label>
            <div className="invite-code-box">{inviteCode || 'Generating...'}</div>
          </div>
        )}
        <div style={{display: 'flex', gap: '10px', marginTop: '10px'}}>
          <button onClick={close} style={{flex: 1, background: '#4f545c', color: 'white', padding: '12px'}}>Cancel</button>
          <button onClick={saveServer} style={{flex: 1, background: themeColor, color: 'white', padding: '12px'}}>Save Changes</button>
        </div>
      </div>
    </div>
  )
}

function MainApp({ themeColor, setThemeColor }) {
  const [currentServer, setCurrentServer] = useState(null);
  const [currentChannel, setCurrentChannel] = useState(null);
  const [showSettings, setShowSettings] = useState(false);
  const [editingServer, setEditingServer] = useState(null);
  
  const isAdmin = auth.currentUser && auth.currentUser.email === 'vincentr111222@gmail.com';
  const serversRef = firestore.collection('servers');
  const [allServers] = useCollectionData(serversRef.orderBy('createdAt'), { idField: 'id' });

  const servers = allServers ? allServers.filter(s => 
    isAdmin || !s.isPrivate || (s.members && s.members.includes(auth.currentUser.uid))
  ) : [];

  useEffect(() => {
    if (servers && servers.length > 0 && !currentServer) setCurrentServer(servers[0]);
  }, [servers, currentServer]);

  const addServer = async () => {
    const name = prompt("Enter Server Name:");
    if (name) await serversRef.add({ name, icon: name.charAt(0).toUpperCase(), isPrivate: false, createdAt: firebase.firestore.FieldValue.serverTimestamp() });
  };

  const deleteServer = async (e, id) => {
    e.stopPropagation();
    if (window.confirm("Delete this entire server?")) {
      await serversRef.doc(id).delete();
      if (currentServer && currentServer.id === id) setCurrentServer(null);
    }
  };

  const joinServerViaCode = async () => {
    const code = prompt("Enter 6-digit Invite Code:");
    if (!code) return;
    const matchedServer = allServers.find(s => s.inviteCode === code.toUpperCase());
    if (matchedServer) {
      await serversRef.doc(matchedServer.id).update({ members: firebase.firestore.FieldValue.arrayUnion(auth.currentUser.uid) });
      alert(`Successfully joined ${matchedServer.name}!`);
    } else alert("Invalid or expired invite code.");
  };

  return (
    <div className="discord-layout">
      {showSettings && <SettingsModal close={() => setShowSettings(false)} themeColor={themeColor} setThemeColor={setThemeColor} />}
      {editingServer && <ServerSettingsModal server={editingServer} close={() => setEditingServer(null)} themeColor={themeColor} />}
      
      <div className="sidebar">
        {servers && servers.map(s => (
          <div key={s.id} className={`server-icon ${currentServer && currentServer.id === s.id ? 'active' : ''}`} onClick={() => { setCurrentServer(s); setCurrentChannel(null); }} title={s.name}>
            {s.icon}
            {isAdmin && (
              <div className="server-actions">
                <button className="action-btn edit-btn" onClick={(e) => { e.stopPropagation(); setEditingServer(s); }}>⚙</button>
                <button className="action-btn del-btn-server" onClick={(e) => deleteServer(e, s.id)}>✕</button>
              </div>
            )}
          </div>
        ))}
        {isAdmin && <div className="server-icon server-add-btn" onClick={addServer}>+</div>}
        {!isAdmin && <div className="server-icon server-join-btn" onClick={joinServerViaCode} title="Join a Server">Join</div>}
      </div>

      {currentServer ? (
        <ServerContent server={currentServer} currentChannel={currentChannel} setCurrentChannel={setCurrentChannel} isAdmin={isAdmin} themeColor={themeColor} openSettings={() => setShowSettings(true)} />
      ) : (
        <div style={{flexGrow: 1, display: 'flex', justifyContent: 'center', alignItems: 'center', backgroundColor: '#36393f'}}><h2 style={{color: '#8e9297'}}>No server selected.</h2></div>
      )}
    </div>
  );
}

function ServerContent({ server, currentChannel, setCurrentChannel, isAdmin, themeColor, openSettings }) {
  const dummy = useRef();
  const initialLoad = useRef(true);
  const [formValue, setFormValue] = useState('');
  const [imgUrlForm, setImgUrlForm] = useState('');
  const [showLinkInput, setShowLinkInput] = useState(false);
  const [cooldown, setCooldown] = useState(0);
  const [mobileNav, setMobileNav] = useState(false);
  const [showMembers, setShowMembers] = useState(false);

  const channelsRef = firestore.collection(`servers/${server.id}/channels`);
  const [channels] = useCollectionData(channelsRef.orderBy('createdAt'), { idField: 'id' });

  const messagesRef = currentChannel ? firestore.collection(`servers/${server.id}/channels/${currentChannel.id}/messages`) : null;
  const [messages] = useCollectionData(messagesRef ? messagesRef.orderBy('createdAt').limit(50) : null, { idField: 'id' });

  const [allUsers] = useCollectionData(firestore.collection('users'));

  // Notification Logic
  useEffect(() => {
    if (initialLoad.current) {
      if (messages && messages.length > 0) initialLoad.current = false;
      return;
    }
    if (messages && messages.length > 0) {
      const lastMsg = messages[messages.length - 1];
      if (lastMsg.uid !== auth.currentUser.uid && Notification.permission === "granted") {
        new Notification(`New message in #${currentChannel.name}`, {
          body: `${lastMsg.displayName}: ${lastMsg.text || 'sent an image'}`,
          icon: 'https://assets-global.website-files.com/6257adef93867e50d84d30e2/636e0a6a49cf127bf92de1e2_icon_clyde_blurple_RGB.png'
        });
      }
    }
  }, [messages, currentChannel]);

  useEffect(() => {
    if (channels && channels.length > 0 && !currentChannel) setCurrentChannel(channels[0]);
  }, [channels, currentChannel, setCurrentChannel]);

  useEffect(() => {
    let timer;
    if (cooldown > 0) timer = setTimeout(() => setCooldown(cooldown - 1), 1000);
    return () => clearTimeout(timer);
  }, [cooldown]);

  const sendMessage = async (e) => {
    e.preventDefault();
    if ((!formValue.trim() && !imgUrlForm.trim()) || cooldown > 0 || !messagesRef) return;
    
    const { uid, photoURL, displayName, email } = auth.currentUser;
    await messagesRef.add({
      text: formValue, imgUrl: imgUrlForm.trim() || null, createdAt: firebase.firestore.FieldValue.serverTimestamp(),
      uid, photoURL: photoURL || 'https://api.adorable.io/avatars/23/abott@adorable.png', displayName: displayName || (email ? email.split('@')[0] : 'Anonymous')
    });

    setFormValue(''); setImgUrlForm(''); setShowLinkInput(false); setCooldown(3);
    if (dummy.current) dummy.current.scrollIntoView({ behavior: 'smooth' });
  }

  // Filter members list based on server privacy
  const visibleMembers = allUsers ? allUsers.filter(u => !server.isPrivate || (server.members && server.members.includes(u.uid)) || isAdmin) : [];

  return (
    <>
      <div className={`mobile-overlay ${mobileNav || showMembers ? 'open' : ''}`} onClick={() => {setMobileNav(false); setShowMembers(false);}}></div>
      <div className={`channels ${mobileNav ? 'open' : ''}`}>
        <div className="channels-header">
          <h3>{server.name}</h3>
          {isAdmin && <button className="add-btn" onClick={async () => { const n = prompt("Name:"); if(n) await channelsRef.add({name: n.toLowerCase(), createdAt: firebase.firestore.FieldValue.serverTimestamp()}); }}>+</button>}
        </div>
        <div className="channel-list">
          {channels && channels.map(c => (
            <div key={c.id} className={`channel ${currentChannel && currentChannel.id === c.id ? 'active' : ''}`} onClick={() => {setCurrentChannel(c); setMobileNav(false);}}>
              <span className="channel-name"><span className="hash-icon">#</span> {c.name}</span>
              {isAdmin && <button className="del-btn" onClick={async (e) => { e.stopPropagation(); if(window.confirm("Delete?")) await channelsRef.doc(c.id).delete(); }}>X</button>}
            </div>
          ))}
        </div>
        <div className="user-panel">
          <div className="user-panel-info">
            <img src={auth.currentUser?.photoURL || 'https://api.adorable.io/avatars/23/abott@adorable.png'} alt="PFP" />
            <div><strong>{auth.currentUser?.displayName || auth.currentUser?.email?.split('@')[0]}</strong></div>
          </div>
          <button className="settings-btn" onClick={openSettings} style={{color: themeColor}}>⚙️</button>
        </div>
      </div>

      <div className="chat-container">
        {currentChannel ? (
          <>
            <header>
              <button className="mobile-nav-toggle" onClick={() => setMobileNav(!mobileNav)}>☰</button>
              <div className="header-title"><span className="hash-icon">#</span> {currentChannel.name}</div>
              <button className="member-toggle" onClick={() => setShowMembers(!showMembers)} style={{display: 'block'}}>👥</button>
            </header>
            <main>
              {messages && messages.map(msg => (
                <ChatMessage key={msg.id} message={msg} currentUserUid={auth.currentUser.uid} isAdmin={isAdmin} onDelete={() => messagesRef.doc(msg.id).delete()} />
              ))}
              <span ref={dummy}></span>
            </main>
            <div className="form-wrapper">
              {showLinkInput && <div className="url-input-container"><input type="text" placeholder="Paste Image URL" value={imgUrlForm} onChange={(e) => setImgUrlForm(e.target.value)} /></div>}
              <form onSubmit={sendMessage}>
                <button type="button" className={`link-btn ${showLinkInput ? 'active' : ''}`} onClick={() => setShowLinkInput(!showLinkInput)} style={{color: showLinkInput ? themeColor : ''}}>🔗</button>
                <input type="text" value={cooldown > 0 ? `Wait ${cooldown}s...` : formValue} onChange={(e) => setFormValue(e.target.value)} placeholder={`Message #${currentChannel.name}`} disabled={cooldown > 0} style={{opacity: cooldown > 0 ? 0.5 : 1}} />
                <button type="submit" style={{display: 'none'}}></button>
              </form>
            </div>
          </>
        ) : ( <div style={{flexGrow: 1, display: 'flex', justifyContent: 'center', alignItems: 'center'}}><h3 style={{color: '#8e9297'}}>Select a channel</h3></div> )}
      </div>

      {/* Member List Right Sidebar */}
      <div className={`member-list ${showMembers ? 'open' : ''}`}>
        <div className="member-group-title">Members — {visibleMembers.length}</div>
        {visibleMembers.map(u => (
          <div className="member-item" key={u.uid}>
            <img src={u.photoURL || 'https://api.adorable.io/avatars/23/abott@adorable.png'} alt="user" />
            <span>{u.displayName}</span>
          </div>
        ))}
      </div>
    </>
  )
}

function ChatMessage({ message, currentUserUid, isAdmin, onDelete }) {
  const { text, imgUrl, photoURL, displayName, uid } = message;
  return (
    <div className="message" style={{justifyContent: 'space-between'}}>
      <div style={{display: 'flex'}}>
        <img className="message-avatar" src={photoURL} alt="user" />
        <div className="message-content">
          <span className="msg-author">{displayName}</span>
          {text && <p>{text}</p>}
          {imgUrl && <img src={imgUrl} className="msg-img" alt="attachment" onClick={() => window.open(imgUrl, '_blank')} />}
        </div>
      </div>
      {(uid === currentUserUid || isAdmin) && <button onClick={onDelete} style={{background: 'transparent', border: 'none', color: '#ed4245', cursor: 'pointer', opacity: 0.7}}>Del</button>}
    </div>
  )
}
export default App;
